export function normalizeSkillName(name: string): string {
  return name.toLowerCase().replace(/[^a-z0-9]/g, '');
}

export function getSkillIconId(cls: string, normalizedName: string): number | null {
  return SKILL_ICON_MAP[cls.toLowerCase()]?.[normalizedName] ?? null;
}
